import os
import sqlite3
import shutil
from flask import Flask, render_template, request, jsonify, session, redirect, url_for
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

DB_PATH = '/tmp/vertex_aero.db'

def get_db_connection():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def security_filter(data):
    # Legacy WAF implementation: strips dangerous keywords (non-recursive)
    blacklist = ["SELECT", "UNION", "WHERE", "LIMIT", "HEX", "SUBSTR", "OR", "AND"]
    if not data:
        return "log_date"

    filtered = data
    for word in blacklist:
        # Case insensitive replacement
        import re
        insens_re = re.compile(re.escape(word), re.IGNORECASE)
        filtered = insens_re.sub('', filtered)
    return filtered

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        # Simulated login for functionality
        session['user'] = 'maintenance_staff'
        return redirect(url_for('dashboard'))
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html')

@app.route('/inventory')
def inventory():
    if 'user' not in session:
        return redirect(url_for('login'))
    conn = get_db_connection()
    parts = conn.execute('SELECT * FROM inventory').fetchall()
    conn.close()
    return render_template('inventory.html', parts=parts)

@app.route('/logs')
def logs():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('logs.html')

@app.route('/api/v1/maintenance/reports')
def maintenance_reports():
    if 'user' not in session:
        return jsonify({"error": "Unauthorized"}), 401

    sort_key = request.args.get('sort', 'log_date')
    clean_sort = security_filter(sort_key)

    conn = get_db_connection()
    try:
        # Vulnerable ORDER BY injection
        query = f"SELECT id, tail_number, log_date, status, technician_id FROM maintenance_logs ORDER BY {clean_sort}"
        logs = conn.execute(query).fetchall()
        return jsonify([dict(row) for row in logs])
    except Exception as e:
        return jsonify({"error": "Query execution failed", "details": str(e)}), 500
    finally:
        conn.close()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

