{% extends "base.html" %}
{% block content %}
<div class="card">
    <div style="display: flex; justify-content: space-between; align-items: center;">
        <h2>Maintenance History</h2>
        <div>
            <label>Sort By:</label>
            <select id="sortSelect" onchange="loadLogs()">
                <option value="log_date">Date</option>
                <option value="id">Report ID</option>
            </select>
        </div>
    </div>
    <table id="logsTable">
        <thead>
            <tr>
                <th>ID</th>
                <th>Tail Number</th>
                <th>Date</th>
                <th>Status</th>
                <th>Technician</th>
            </tr>
        </thead>
        <tbody>
            <!-- Loaded via API -->
        </tbody>
    </table>
</div>
<script>
function loadLogs() {
    const sort = document.getElementById('sortSelect').value;
    fetch(`/api/v1/maintenance/reports?sort=${sort}`)
        .then(r => r.json())
        .then(data => {
            const tbody = document.querySelector('#logsTable tbody');
            tbody.innerHTML = '';
            data.forEach(log => {
                const row = `<tr>
                    <td>${log.id}</td>
                    <td>${log.tail_number}</td>
                    <td>${log.log_date}</td>
                    <td><span class="status-${log.status.toLowerCase()}">${log.status}</span></td>
                    <td>${log.technician_id}</td>
                </tr>`;
                tbody.innerHTML += row;
            });
        });
}
document.addEventListener('DOMContentLoaded', loadLogs);
</script>
{% endblock %}
